<template>
  <div class="analytics-dashboard">
    <div class="dashboard-header">
      <h2>Analytics Dashboard</h2>
    </div>
    
    <div class="dashboard-tabs">
      <button 
        v-for="(tab, index) in tabs" 
        :key="index"
        :class="['tab-button', { active: activeTab === index }]"
        @click="switchTab(index)"
      >
        <i :class="tab.icon"></i>
        {{ tab.label }}
      </button>
    </div>

    <div class="dashboard-content">
      <RevenueAnalytics v-if="activeTab === 0" />
      <ProcessingAnalytics v-if="activeTab === 1" />
      <CustomerAnalytics v-if="activeTab === 2" />
    </div>
  </div>
</template>

<script>
import RevenueAnalytics from './components/RevenueAnalytics.vue';
import ProcessingAnalytics from './components/ProcessingAnalytics.vue';
import CustomerAnalytics from './components/CustomerAnalytics.vue';

export default {
  name: 'AnalyticsDashboard',
  components: {
    RevenueAnalytics,
    ProcessingAnalytics,
    CustomerAnalytics
  },
  data() {
    return {
      activeTab: 0,
      tabs: [
        { label: 'Revenue Analytics', icon: 'fa fa-money-bill-trend-up' },
        { label: 'Processing Analytics', icon: 'fa fa-cogs' },
        { label: 'Customer Analytics', icon: 'fa fa-users' }
      ]
    };
  },
  methods: {
    switchTab(index) {
      this.activeTab = index;
    }
  }
};
</script>

<style scoped>
.analytics-dashboard {
  padding: 20px;
  background: #f8fafc;
  min-height: calc(100vh - 100px);
}

.dashboard-header {
  margin-bottom: 20px;
}

.dashboard-header h2 {
  color: #003d4d;
  font-size: 28px;
  font-weight: 700;
  margin: 0;
}

.dashboard-tabs {
  display: flex;
  gap: 10px;
  margin-bottom: 30px;
  border-bottom: 2px solid #e1e8ed;
  padding-bottom: 0;
}

.tab-button {
  padding: 12px 24px;
  background: transparent;
  border: none;
  border-bottom: 3px solid transparent;
  color: #7f8c8d;
  font-size: 16px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.3s ease;
  display: flex;
  align-items: center;
  gap: 8px;
}

.tab-button:hover {
  color: #006666;
  background: rgba(0, 102, 102, 0.05);
}

.tab-button.active {
  color: #006666;
  border-bottom-color: #006666;
  background: rgba(0, 102, 102, 0.05);
}

.tab-button i {
  font-size: 18px;
}

.dashboard-content {
  margin-top: 20px;
}
</style>