<template>
  <div class="widget-card">
    <div class="widget-header">
      <div class="widget-title">
        <i class="fas fa-file-invoice-dollar"></i> Bills vs Revenue
      </div>
    </div>
    
    <div v-if="loading" class="loading">Loading...</div>
    <div v-else id="billsVsRevenueChart" class="chart-container"></div>
    
    <div v-if="stats" class="mini-stats">
      <div class="mini-stat">
        <div class="mini-stat-value">{{ stats.billRevenueRatio }}</div>
        <div class="mini-stat-label">Avg Bill/Revenue Ratio</div>
      </div>
      <div class="mini-stat">
        <div class="mini-stat-value">{{ stats.totalBills }}</div>
        <div class="mini-stat-label">Total Bills (All Time)</div>
      </div>
    </div>
  </div>
</template>

<script>
import { analyticsService } from '../../../../services/analyticsService';
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'BillsVsRevenueWidget',
  data() {
    return {
      loading: false,
      stats: null,
      quarters: null,
      revenues: null
    };
  },
  mounted() {
    this.loadData();
  },
  props: {
    QuarterlyTrendAnalysisData: {
      type: Array,
      default: () => []
    }
  },
  methods: {
    async loadData() {
      //debugger
      var vm = this;
      vm.loading = true;
      try {
        vm.quarters = vm.QuarterlyTrendAnalysisData.map(d => d.Quarter_Label);
        vm.revenues = vm.QuarterlyTrendAnalysisData.map(d => d.Total_Bills);
        vm.drawChart();

      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {
        vm.loading = false;
      }
    }, 
    drawChart() {
     //if (!data || !data.quarters) return;
      
      const trace1 = {
        x: this.quarters,
        y: this.revenues,
        name: 'Bills',
        type: 'bar',
        marker: { color: '#3b82f6' }
      };
      
      const trace2 = {
        x: this.quarters,
        y: this.revenues,
        name: 'Revenue',
        type: 'scatter',
        mode: 'lines+markers',
        yaxis: 'y2',
        line: { color: '#10b981', width: 3 }
      };
      
      const layout = {
        margin: { t: 30, b: 60, l: 50, r: 50 },
        paper_bgcolor: 'transparent',
        plot_bgcolor: 'transparent',
        height: 280,
        yaxis: { title: 'Bills' },
        yaxis2: { title: 'Revenue', overlaying: 'y', side: 'r' }
      };
      
      Plotly.newPlot('billsVsRevenueChart', [trace1, trace2], layout, { responsive: true });
    }
  }
};
</script>

<style scoped>
.widget-card {
  background: white;
  border-radius: 10px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.05);
  padding: 20px;
  height: 350px;
  display: flex;
  flex-direction: column;
}

.widget-header {
  margin-bottom: 15px;
}

.widget-title {
  font-size: 16px;
  font-weight: 600;
  color: #003d4d;
  display: flex;
  align-items: center;
  gap: 8px;
}

.widget-title i {
  color: #006666;
}

.chart-container {
  flex: 1;
  min-height: 280px;
}

.loading {
  text-align: center;
  padding: 40px;
  color: #7f8c8d;
}

.mini-stats {
  display: flex;
  gap: 15px;
  margin-top: 15px;
}

.mini-stat {
  flex: 1;
  text-align: center;
  padding: 10px;
  background: #f8fafc;
  border-radius: 6px;
}

.mini-stat-value {
  font-size: 18px;
  font-weight: 700;
  color: #006666;
  margin-bottom: 5px;
}

.mini-stat-label {
  font-size: 12px;
  color: #7f8c8d;
}
</style>