<template>
  <div class="widget-card">
    <div class="widget-header">
      <div class="widget-title">
        <i class="fas fa-user-clock"></i> Agent Performance: Average Ticket Locate Time
      </div>
      <div style="font-size: 14px; color: #7f8c8d; margin-top: 5px;">
        Quarterly average time taken by agents to locate tickets (2020-2024)
      </div>
    </div>
    
    <div id="agentTimeChart" class="chart-container"></div>
    
    <div v-if="stats" class="agent-stats">
      <div class="agent-stat-box">
        <div class="agent-stat-value">{{ stats.AvgLocateTime }} min</div>
        <div class="agent-stat-label">Average Across All Periods</div>
      </div>
      <div class="agent-stat-box">
        <div class="agent-stat-value">{{ stats.peakLocateTime }} min</div>
        <div class="agent-stat-label">Peak Time (Q1 2023)</div>
      </div>
      <div class="agent-stat-box">
        <div class="agent-stat-value">{{ stats.improvementTrend }}</div>
        <div class="agent-stat-label">Increase Since 2020</div>
      </div>
      <div class="agent-stat-box">
        <div class="agent-stat-value">{{ stats.recentPerformance }} min</div>
        <div class="agent-stat-label">Average in 2024</div>
      </div>
    </div>
  </div>
</template>

<script>
import * as Plotly from 'plotly.js-dist';

export default {
  name: 'AgentPerformance',
  data() {
    return {
      loading: false,
      stats: null,
    };
  },
  props: {
    AgentPerformenceData: {
      type: String,
      required: false,
      default: () => []
    }
  },
  mounted() {
    var vm = this;
    vm.loadData();
  },
  methods: {
    loadData() {
      var vm = this;
      vm.loading = true;
      try {
        
        const rawResponse = vm.AgentPerformenceData;
        const level1 = JSON.parse(rawResponse);
        const level2 = JSON.parse(level1[0]);
        const performanceObj = level2.find(item => item.key === "performanceData");
        vm.AgentPerformenceDataextract = JSON.parse(performanceObj.value);

        // Calculate stats
        const avg = vm.AgentPerformenceDataextract.reduce((sum, d) => sum + d.AvgLocateTime, 0) / vm.AgentPerformenceDataextract.length;
        const peak = Math.max(...vm.AgentPerformenceDataextract.map(d => d.AvgLocateTime));
        const peakData = vm.AgentPerformenceDataextract.find(d => d.AvgLocateTime === peak);
        
        const startAvg = (vm.AgentPerformenceDataextract[0].AvgLocateTime + vm.AgentPerformenceDataextract[1].AvgLocateTime + 
                         vm.AgentPerformenceDataextract[2].AvgLocateTime + vm.AgentPerformenceDataextract[3].AvgLocateTime) / 4;
        const endAvg = (vm.AgentPerformenceDataextract[vm.AgentPerformenceDataextract.length-4].AvgLocateTime + 
                       vm.AgentPerformenceDataextract[vm.AgentPerformenceDataextract.length-3].AvgLocateTime + 
                       vm.AgentPerformenceDataextract[vm.AgentPerformenceDataextract.length-2].AvgLocateTime + 
                       vm.AgentPerformenceDataextract[vm.AgentPerformenceDataextract.length-1].AvgLocateTime) / 4;
        const improvement = (((endAvg - startAvg) / startAvg) * 100).toFixed(0);
        
        const recentAvg = vm.AgentPerformenceDataextract.filter(d => d.year === 2024).reduce((sum, d) => sum + d.AvgLocateTime, 0) / 4;
        
        vm.stats = {
          AvgLocateTime: avg.toFixed(2),
          peakLocateTime: peak.toFixed(2),
          improvementTrend: `+${improvement}%`,
          recentPerformance: recentAvg.toFixed(2),
          peakData: peakData
        };
        
        vm.drawChart();
      } catch (error) {
        console.error('Error loading agent performance:', error);
      } finally {
        vm.loading = false;
      }
    },
    drawChart() {
      var vm = this;
      const quarters = vm.AgentPerformenceDataextract.map(d => `Q${d.QUARTER} ${d.YEAR}`);
      const locateTimes = vm.AgentPerformenceDataextract.map(d => d.AvgLocateTime);
      
      const mainTrace = {
        x: quarters,
        y: locateTimes,
        type: 'scatter',
        mode: 'lines+markers',
        name: 'Average Locate Time',
        line: {
          color: '#ec4899',
          width: 3,
          shape: 'spline'
        },
        marker: {
          size: 6,
          color: '#ec4899'
        }
      };
      
      const xValues = vm.AgentPerformenceDataextract.map((_, i) => i);
      const yValues = locateTimes;
      const n = xValues.length;
      
      const sumX = xValues.reduce((a, b) => a + b, 0);
      const sumY = yValues.reduce((a, b) => a + b, 0);
      const sumXY = xValues.reduce((sum, x, i) => sum + x * yValues[i], 0);
      const sumXX = xValues.reduce((sum, x) => sum + x * x, 0);
      
      const slope = (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX);
      const intercept = (sumY - slope * sumX) / n;
      
      const trendY = xValues.map(x => slope * x + intercept);
      
      const trendTrace = {
        x: quarters,
        y: trendY,
        type: 'scatter',
        mode: 'lines',
        name: 'Trend Line',
        line: {
          color: 'rgba(236, 72, 153, 0.5)',
          width: 2,
          dash: 'dash'
        }
      };
      
      const peakAnnotation = {
        x: `Q${vm.stats.peakData.quarter} ${vm.stats.peakData.year}`,
        y: vm.stats.peakData.AvgLocateTime,
        xref: 'x',
        yref: 'y',
        text: `Peak: ${vm.stats.peakData.AvgLocateTime.toFixed(2)} min`,
        showarrow: true,
        arrowhead: 2,
        arrowsize: 1,
        arrowwidth: 2,
        arrowcolor: '#ef4444',
        ax: 0,
        ay: -40,
        bgcolor: 'white',
        bordercolor: '#ef4444',
        borderwidth: 1,
        borderpad: 4,
        font: {
          size: 12,
          color: '#ef4444'
        }
      };
      
      const improvementAnnotation = {
        x: 'Q4 2024',
        y: 5.30,
        xref: 'x',
        yref: 'y',
        text: 'Recent Improvement',
        showarrow: true,
        arrowhead: 2,
        arrowsize: 1,
        arrowwidth: 2,
        arrowcolor: '#10b981',
        ax: 40,
        ay: -30,
        bgcolor: 'white',
        bordercolor: '#10b981',
        borderwidth: 1,
        borderpad: 4,
        font: {
          size: 12,
          color: '#10b981'
        }
      };
      
      const layout = {
        margin: { t: 30, b: 80, l: 80, r: 30 },
        paper_bgcolor: 'transparent',
        plot_bgcolor: 'transparent',
        height: 400,
        xaxis: {
          title: 'Quarter',
          tickangle: -45,
          gridcolor: '#f1f1f1',
          titlefont: { size: 14 },
          tickfont: { size: 12 }
        },
        yaxis: {
          title: 'Average Time (minutes)',
          tickformat: '.2f',
          gridcolor: '#f1f1f1',
          titlefont: { size: 14 },
          tickfont: { size: 12 },
          range: [3.5, 7.0]
        },
        hovermode: 'closest',
        showlegend: true,
        legend: {
          orientation: 'h',
          y: -0.2,
          x: 0.5,
          xanchor: 'center'
        },
        annotations: [peakAnnotation, improvementAnnotation]
      };
      
      Plotly.newPlot('agentTimeChart', [mainTrace, trendTrace], layout, { responsive: true });
    }
  }
};
</script>

<style scoped>
.widget-card {
  background: white;
  border-radius: 10px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.05);
  padding: 20px;
  margin-bottom: 25px;
}

.widget-header {
  margin-bottom: 15px;
}

.widget-title {
  font-size: 16px;
  font-weight: 600;
  color: #003d4d;
  display: flex;
  align-items: center;
  gap: 8px;
}

.widget-title i {
  color: #006666;
}

.chart-container {
  min-height: 400px;
  width: 100%;
}

.loading {
  text-align: center;
  padding: 40px;
  color: #7f8c8d;
}

.agent-stats {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 15px;
  margin-top: 15px;
}

.agent-stat-box {
  text-align: center;
  padding: 15px;
  background: #f8fafc;
  border-radius: 6px;
  border-left: 4px solid #ec4899;
}

.agent-stat-value {
  font-size: 18px;
  font-weight: 700;
  color: #006666;
  margin-bottom: 5px;
}

.agent-stat-label {
  font-size: 12px;
  color: #7f8c8d;
}
</style>
